SET FOREIGN_KEY_CHECKS=0;
SET SQL_MODE='NO_AUTO_VALUE_ON_ZERO';
CREATE TABLE IF NOT EXISTS `migrations` (`id` int(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `migration` varchar(255) not null, `batch` int(11) not null);
CREATE TABLE IF NOT EXISTS `users` (`id` int(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` varchar(255) not null, `email` varchar(255) not null, `email_verified_at` datetime, `password` varchar(255) not null, `remember_token` varchar(255), `created_at` datetime, `updated_at` datetime);
CREATE TABLE IF NOT EXISTS `password_reset_tokens` (`email` varchar(255) not null, `token` varchar(255) not null, `created_at` datetime, primary key (`email`));
CREATE TABLE IF NOT EXISTS `sessions` (`id` varchar(255) not null, `user_id` int(11), `ip_address` varchar(255), `user_agent` text, `payload` text not null, `last_activity` int(11) not null, primary key (`id`));
CREATE TABLE IF NOT EXISTS `cache` (`key` varchar(255) not null, `value` text not null, `expiration` int(11) not null, primary key (`key`));
CREATE TABLE IF NOT EXISTS `cache_locks` (`key` varchar(255) not null, `owner` varchar(255) not null, `expiration` int(11) not null, primary key (`key`));
CREATE TABLE IF NOT EXISTS `jobs` (`id` int(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `queue` varchar(255) not null, `payload` text not null, `attempts` int(11) not null, `reserved_at` int(11), `available_at` int(11) not null, `created_at` int(11) not null);
CREATE TABLE IF NOT EXISTS `job_batches` (`id` varchar(255) not null, `name` varchar(255) not null, `total_jobs` int(11) not null, `pending_jobs` int(11) not null, `failed_jobs` int(11) not null, `failed_job_ids` text not null, `options` text, `cancelled_at` int(11), `created_at` int(11) not null, `finished_at` int(11), primary key (`id`));
CREATE TABLE IF NOT EXISTS `failed_jobs` (`id` int(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `uuid` varchar(255) not null, `connection` varchar(255) not null, `queue` varchar(255) not null, `payload` text not null, `exception` text not null, `failed_at` datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS `menu_items` (`id` int(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` varchar(255) not null, `description` text, `category` varchar(255) not null, `price` decimal(10,2) not null, `image` varchar(255), `prep_time` int(11) default '20', `rating` decimal(10,2) not null default '4.5', `is_available` tinyint(1) not null default '1', `is_featured` tinyint(1) not null default '0', `created_at` datetime, `updated_at` datetime);
CREATE TABLE IF NOT EXISTS `order_items` (`id` int(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `order_id` int(11) not null, `menu_item_id` int(11) not null, `name` varchar(255) not null, `price` decimal(10,2) not null, `quantity` int(11) not null, `subtotal` decimal(10,2) not null, `created_at` datetime, `updated_at` datetime, foreign key(`order_id`) references `orders`(`id`) on delete cascade, foreign key(`menu_item_id`) references `menu_items`(`id`) on delete cascade);
CREATE TABLE IF NOT EXISTS `personal_access_tokens` (`id` int(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `tokenable_type` varchar(255) not null, `tokenable_id` int(11) not null, `name` text not null, `token` varchar(255) not null, `abilities` text, `last_used_at` datetime, `expires_at` datetime, `created_at` datetime, `updated_at` datetime);
CREATE TABLE IF NOT EXISTS `categories` (`id` int(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` varchar(255) not null, `slug` varchar(255) not null, `emoji` varchar(255) not null default '🍽️', `description` text, `is_active` tinyint(1) not null default '1', `sort_order` int(11) not null default '0', `created_at` datetime, `updated_at` datetime);
CREATE TABLE IF NOT EXISTS `marketing_cards` (`id` int(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `tag` varchar(255) not null default 'PROMO', `title` varchar(255) not null, `description` text, `price` varchar(255), `menu_item_id` int(11), `video_url` varchar(255), `image_path` varchar(255), `is_active` tinyint(1) not null default '1', `sort_order` int(11) not null default '0', `created_at` datetime, `updated_at` datetime, foreign key(`menu_item_id`) references `menu_items`(`id`) on delete set null);
CREATE TABLE IF NOT EXISTS `delivery_fee_settings` (`id` int(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `min_distance_km` decimal(10,2) not null default '0', `max_distance_km` decimal(10,2), `delivery_fee` decimal(10,2) not null default '0', `created_at` datetime, `updated_at` datetime, `min_order_amount` decimal(10,2) not null default '0');
CREATE TABLE IF NOT EXISTS `orders` (`id` int(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `order_number` varchar(255) not null, `customer_name` varchar(255) not null, `customer_email` varchar(255), `customer_phone` varchar(255) not null, `delivery_address` text not null, `city` varchar(255) not null, `subtotal` decimal(10,2) not null, `delivery_fee` decimal(10,2) not null default '2.99', `total` decimal(10,2) not null, `status` varchar(255) not null default ('pending'), `payment_method` varchar(255) not null default ('cash_on_delivery'), `special_instructions` text, `estimated_delivery_at` datetime, `created_at` datetime, `updated_at` datetime, `latitude` decimal(10,2), `longitude` decimal(10,2), `prep_time_minutes` int(11), `order_type` varchar(255) not null default 'delivery', `table_number` varchar(255), `pickup_time` varchar(255), `distance_km` numeric);
CREATE TABLE IF NOT EXISTS `reviews` (`id` int(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `menu_item_id` int(11) not null, `customer_name` varchar(255) not null, `customer_phone` varchar(255), `rating` int(11) not null default '5', `comment` text not null, `is_approved` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime, `admin_reply` text, foreign key(`menu_item_id`) references `menu_items`(`id`) on delete cascade);
CREATE TABLE IF NOT EXISTS `receipt_settings` (`id` int(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `outlet_name` varchar(255) not null default 'SWAD E PUNJAB', `outlet_address` text, `outlet_phone` varchar(255), `gst_number` varchar(255), `footer_message` varchar(255), `created_at` datetime, `updated_at` datetime, `whatsapp_gateway_url` varchar(255), `whatsapp_gateway_token` varchar(255), `whatsapp_gateway_payload_template` text, `whatsapp_gateway_image_url` varchar(255), `google_maps_api_key` varchar(255), `delivery_base_km` decimal(10,2) not null default '3', `delivery_base_fee` decimal(10,2) not null default '30', `delivery_extra_fee_per_km` decimal(10,2) not null default '10', `delivery_max_distance` decimal(10,2) not null default '15', `delivery_fallback_fee` decimal(10,2) not null default '50');
CREATE UNIQUE INDEX `users_email_unique` on `users` (`email`);
CREATE INDEX `sessions_user_id_index` on `sessions` (`user_id`);
CREATE INDEX `sessions_last_activity_index` on `sessions` (`last_activity`);
CREATE INDEX `cache_expiration_index` on `cache` (`expiration`);
CREATE INDEX `cache_locks_expiration_index` on `cache_locks` (`expiration`);
CREATE INDEX `jobs_queue_index` on `jobs` (`queue`);
CREATE INDEX `failed_jobs_connection_queue_failed_at_index` on `failed_jobs` (`connection`, `queue`, `failed_at`);
CREATE UNIQUE INDEX `failed_jobs_uuid_unique` on `failed_jobs` (`uuid`);
CREATE INDEX `personal_access_tokens_tokenable_type_tokenable_id_index` on `personal_access_tokens` (`tokenable_type`, `tokenable_id`);
CREATE UNIQUE INDEX `personal_access_tokens_token_unique` on `personal_access_tokens` (`token`);
CREATE INDEX `personal_access_tokens_expires_at_index` on `personal_access_tokens` (`expires_at`);
CREATE UNIQUE INDEX `categories_slug_unique` on `categories` (`slug`);
CREATE UNIQUE INDEX `orders_order_number_unique` on `orders` (`order_number`);

SET FOREIGN_KEY_CHECKS=1;
